import React, { useState, useEffect, useRef } from 'react';
import Logo from './Logo.png'; 

const gold = '#D4AF37'; 
const terracotta = '#C04000'; 

function App() {
  const [activeCategory, setActiveCategory] = useState('Small Chops');
  const [currentSlide, setCurrentSlide] = useState(0);
  const [cart, setCart] = useState([]);
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false); // Controls the new Payment Pop-up
  const [deliveryMode, setDeliveryMode] = useState('Pickup');
  const [scheduledDate, setScheduledDate] = useState('');
  const [address, setAddress] = useState('');
  const [deliveryZone, setDeliveryZone] = useState('Ikeja, Lagos');
  
  const inputRef = useRef();
  const autoCompleteRef = useRef();
  const whatsappNumber = "2349122731172";
  const bankInfo = { bank: "PREMIUMTRUST BANK", account: "0112326977", name: "OLUKOYA OMOTOYOSI" };

  const slides = [
    { title: "EVERY BITE, ALWAYS WORTH IT!", subtitle: "NIGERIA'S FAVORITE GRILLS & SMALL CHOPS.", img: "/images/chops_promo.png", bg: terracotta },
    { title: "AFFORDABLE LUXURY WIGS.", subtitle: "Wigs anyone can afford😊!", img: "/images/wigs_promo.png", bg: "#8B0000" },
    { title: "PREMIUM TASTE, 9JA FLAVOR!", subtitle: "THE PERFECT BALANCE OF GOOD FOOD.", img: "/images/lunch_promo.png", bg: terracotta }
  ];

  const menuData = {
    CHOPS: [
      { id: 1, name: "The Starter Pack", price: "15,000", desc: "7 Samosas, 7 Springrolls, 15 Puff-puff, 10 Mosa, 4 Grilled Chicken.", img: "/images/starter.jpg" },
      { id: 2, name: "The Signature Platter", price: "25,000", desc: "10 Samosas, 10 Springrolls, 25 Puff-puff, 20 Mosa, 8 Grilled Chicken.", img: "/images/signature.jpg" }
    ],
    WIGS: [
      { type: "Human Hair", items: [
          { id: 201, name: "Raw Cambodian", price: "85,000", desc: "14\" Frontal Unit", img: "/images/hair1.jpg" }
      ]}
    ]
  };

  // Google Maps Logic
  useEffect(() => {
    if (window.google) {
      autoCompleteRef.current = new window.google.maps.places.Autocomplete(inputRef.current, {
        componentRestrictions: { country: "ng" },
        fields: ["formatted_address"]
      });
      autoCompleteRef.current.addListener("place_changed", () => {
        const place = autoCompleteRef.current.getPlace();
        setAddress(place.formatted_address);
      });
    }
  }, []);

  const addToCart = (item) => setCart([...cart, item]);
  const total = cart.reduce((acc, item) => acc + parseInt(item.price.replace(/,/g, '')), 0);

  // FINAL STEP: Triggers WhatsApp
  const sendToWhatsApp = () => {
    const itemsList = cart.map(item => `- ${item.name} (₦${item.price})`).join('%0A');
    const orderTime = scheduledDate ? `📅 Scheduled: ${scheduledDate}` : "🚀 Instant Delivery";
    const deliveryInfo = deliveryMode === 'Delivery' ? `📍 Zone: ${deliveryZone}%0A🏠 Address: ${address}` : "🏢 Method: Pickup";

    const message = `Hello Àmí by T!%0A%0A*New Order Request*%0A------------------%0A*Time:* ${orderTime}%0A*Method:* ${deliveryMode}%0A${deliveryInfo}%0A%0A*Items:*%0A${itemsList}%0A%0A*Total:* ₦${total.toLocaleString()}%0A%0A*Payment status:* Transfer Initiated to ${bankInfo.bank}`;
    
    window.open(`https://wa.me/${whatsappNumber}?text=${message}`, '_blank');
  };

  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', color: '#fff', fontFamily: 'system-ui, sans-serif' }}>
      
      {/* HEADER */}
      <header style={{ padding: '15px 20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', position: 'sticky', top: 0, backgroundColor: '#000', zIndex: 1000, borderBottom: '1px solid #1a1a1a' }}>
        <img src={Logo} alt="Logo" style={{ height: '45px' }} />
        <div style={{ fontSize: '1.4rem' }}>🛒 {cart.length}</div>
      </header>

      {/* BANNER & INFO SECTIONS (Simplified for brevity) */}
      <div style={{ padding: '20px' }}>
        <h1 style={{ fontSize: '1.6rem', fontWeight: '800' }}>Àmí by T</h1>
        <input ref={inputRef} placeholder="Delivery Address..." style={{ width: '100%', marginTop: '10px', padding: '12px', borderRadius: '10px', border: '1px solid #333', background: '#111', color: '#fff' }} />
        
        <div style={{ display: 'flex', marginTop: '15px', backgroundColor: '#111', borderRadius: '12px', padding: '4px' }}>
          <button onClick={() => setDeliveryMode('Pickup')} style={{ flex: 1, padding: '12px', borderRadius: '10px', border: 'none', backgroundColor: deliveryMode === 'Pickup' ? '#fff' : 'transparent', color: deliveryMode === 'Pickup' ? '#000' : '#888', fontWeight: '800' }}>Pickup</button>
          <button onClick={() => setDeliveryMode('Delivery')} style={{ flex: 1, padding: '12px', borderRadius: '10px', border: 'none', backgroundColor: deliveryMode === 'Delivery' ? '#fff' : 'transparent', color: deliveryMode === 'Delivery' ? '#000' : '#888', fontWeight: '800' }}>Delivery</button>
        </div>
      </div>

      {/* MENU */}
      <main style={{ padding: '0 20px 120px' }}>
        {menuData.CHOPS.map((item) => (
          <div key={item.id} style={{ display: 'flex', padding: '15px 0', borderBottom: '1px solid #1a1a1a' }}>
            <div style={{ flex: 1 }}>
              <h4 style={{ margin: 0 }}>{item.name}</h4>
              <div style={{ color: gold }}>₦{item.price}</div>
            </div>
            <button onClick={() => addToCart(item)} style={{ backgroundColor: terracotta, color: '#fff', border: 'none', padding: '8px 15px', borderRadius: '15px', fontWeight: '900' }}>ADD</button>
          </div>
        ))}
      </main>

      {/* FLOATING BAR: Now opens the Checkout Overlay instead of WhatsApp */}
      {cart.length > 0 && (
        <div onClick={() => setIsCheckoutOpen(true)} style={{ position: 'fixed', bottom: '25px', left: '50%', transform: 'translateX(-50%)', width: '92%', backgroundColor: terracotta, padding: '20px', borderRadius: '20px', display: 'flex', justifyContent: 'space-between', fontWeight: '900', zIndex: 1001, cursor: 'pointer' }}>
          <span>{cart.length} ITEMS</span>
          <span>CHECKOUT ₦{total.toLocaleString()}</span>
        </div>
      )}

      {/* NEW: CHECKOUT & PAYMENT OVERLAY */}
      {isCheckoutOpen && (
        <div style={{ position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', backgroundColor: 'rgba(0,0,0,0.9)', zIndex: 2000, display: 'flex', alignItems: 'flex-end' }}>
          <div style={{ width: '100%', backgroundColor: '#111', borderTopLeftRadius: '30px', borderTopRightRadius: '30px', padding: '30px 20px', boxSizing: 'border-box' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
              <h2 style={{ margin: 0 }}>Order Summary</h2>
              <button onClick={() => setIsCheckoutOpen(false)} style={{ background: 'none', border: 'none', color: '#888', fontSize: '1.5rem' }}>✕</button>
            </div>

            {/* BANK DETAILS SECTION */}
            <div style={{ padding: '20px', backgroundColor: '#1a1a1a', borderRadius: '20px', border: `1px solid ${gold}`, marginBottom: '20px' }}>
              <p style={{ color: gold, fontSize: '0.8rem', fontWeight: 'bold', margin: '0 0 10px 0' }}>TRANSFER TO ACCOUNT:</p>
              <h3 style={{ margin: 0, fontSize: '1.2rem' }}>{bankInfo.bank}</h3>
              <p style={{ margin: '5px 0', fontSize: '1.5rem', fontWeight: '900', color: gold, letterSpacing: '1px' }}>{bankInfo.account}</p>
              <p style={{ margin: 0, opacity: 0.8 }}>{bankInfo.name}</p>
            </div>

            <div style={{ marginBottom: '30px' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', padding: '10px 0' }}>
                <span>Subtotal</span>
                <span>₦{total.toLocaleString()}</span>
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between', fontWeight: '900', fontSize: '1.2rem', marginTop: '10px' }}>
                <span>Total</span>
                <span>₦{total.toLocaleString()}</span>
              </div>
            </div>

            <button onClick={sendToWhatsApp} style={{ width: '100%', padding: '20px', backgroundColor: terracotta, color: '#fff', borderRadius: '15px', border: 'none', fontWeight: '900', fontSize: '1rem' }}>
              SEND RECEIPT TO WHATSAPP
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
